  "ZeptoHeaderV1/ZeptoHeaderV1.styles.ts": "import { StyleSheet } from 'react-native';\nimport type { SemanticTokens } from '@my-ui-lib/tokens';\n\nexport function createZeptoHeaderV1Styles(theme: SemanticTokens) {\n  const { spacing, fontSizes, fontWeights, radii } = theme;\n\n  return StyleSheet.create({\n    root: {\n      width: '100%',\n    },\n    row: {\n      flexDirection: 'row',\n      alignItems: 'center',\n      justifyContent: 'space-between',\n      paddingHorizontal: spacing[4],\n      paddingVertical: spacing[3],\n      gap: spacing[3],\n    },\n    left: {\n      flex: 1,\n      minWidth: 0,\n      gap: spacing[1],\n    },\n    etaRow: {\n      flexDirection: 'row',\n      alignItems: 'center',\n      gap: spacing[1],\n    },\n    etaText: {\n      fontSize: fontSizes.md,\n      fontWeight: fontWeights.bold as '700',\n      letterSpacing: -0.2,\n    },\n    addressRow: {\n      flexDirection: 'row',\n      alignItems: 'center',\n      gap: spacing[1],\n      marginTop: 2,\n    },\n    addressText: {\n      flex: 1,\n      minWidth: 0,\n      fontSize: fontSizes.sm,\n      fontWeight: fontWeights.regular as '400',\n      letterSpacing: -0.1,\n    },\n    right: {\n      flexDirection: 'row',\n      alignItems: 'center',\n      gap: spacing[2],\n    },\n    walletRow: {\n      flexDirection: 'row',\n      alignItems: 'center',\n      gap: spacing[2],\n    },\n    walletAmount: {\n      fontSize: fontSizes.md,\n      fontWeight: fontWeights.bold as '700',\n      letterSpacing: -0.2,\n    },\n    profileTouch: {\n      borderRadius: radii.full,\n    },\n  });\n}\n",
